412→// Step 5: Incremental settle for a single user
413→// ══════════════════════════════════════════════════════════════════════
414→export async function incrementalSettleForUser(userId) {
415→    if (!userId) return;
416→
417→    try {
418→        // 1. Recompute this user's centroid
419→        const { data: posts } = await supabase
420→            .from('journals')
421→            .select('embeddings')
422→            .eq('user_id', userId)
423→            .eq('privacy', 'public')
424→            .not('embeddings', 'is', null);
425→
426→        if (!posts || posts.length === 0) return;
427→
428→        const dim = 384;
429→        const mean = new Array(dim).fill(0);
430→        let validCount = 0;
431→        for (const post of posts) {
432→            const emb = post.embeddings;
433→            if (!emb || emb.length !== dim) continue;
434→            for (let i = 0; i < dim; i++) mean[i] += emb[i];
435→            validCount++;
436→        }
437→        if (validCount === 0) return;
438→
439→        for (let i = 0; i < dim; i++) mean[i] /= validCount;
440→
441→        // Normalize
442→        let norm = 0;
443→        for (let i = 0; i < dim; i++) norm += mean[i] * mean[i];
444→        norm = Math.sqrt(norm);
445→        if (norm > 0) {
446→            for (let i = 0; i < dim; i++) mean[i] /= norm;
447→        }
448→
449→        const vectorStr = `[${mean.join(',')}]`;
450→
451→        // Get or create initial position from hash
452→        const { data: existing } = await supabase
453→            .from('galaxy_centroids')
454→            .select('galaxy_x, galaxy_y')
455→            .eq('user_id', userId)
456→            .single();
457→
458→        const home = userHomeCoords(userId);
459→
460→        await supabase.from('galaxy_centroids').upsert({
461→            user_id: userId,
462→            mean_embedding: vectorStr,
463→            galaxy_x: existing?.galaxy_x ?? home.x,
464→            galaxy_y: existing?.galaxy_y ?? home.y,
465→            post_count: validCount,
466→            updated_at: new Date().toISOString()
467→        }, { onConflict: 'user_id' });
468→
469→        // 2. Recompute edges for this user against all other centroids
470→        const { data: allCentroids } = await supabase
471→            .from('galaxy_centroids')
472→            .select('user_id, mean_embedding')
473→            .not('mean_embedding', 'is', null)
474→            .neq('user_id', userId);
475→
476→        if (allCentroids && allCentroids.length > 0) {
477→            const newEdges = [];
478→            for (const other of allCentroids) {
479→                const embB = Array.isArray(other.mean_embedding) ? other.mean_embedding : null;
480→                if (!embB) continue;
481→
482→                const similarity = dot(mean, embB);
483→                if (similarity >= 0.25) {
484→                    const [userA, userB] = userId < other.user_id
485→                        ? [userId, other.user_id]
486→                        : [other.user_id, userId];
487→                    newEdges.push({ user_a: userA, user_b: userB, similarity });
488→                }
489→            }
490→
491→            // Delete old edges involving this user
492→            await supabase.from('galaxy_edges').delete().or(`user_a.eq.${userId},user_b.eq.${userId}`);
493→
494→            if (newEdges.length > 0) {
495→                await supabase.from('galaxy_edges').upsert(newEdges, { onConflict: 'user_a,user_b' });
496→            }
497→        }
498→
499→        // 3. Re-settle this user's star positions (use current galaxy position)
500→        const { data: centroid } = await supabase
501→            .from('galaxy_centroids')
502→            .select('galaxy_x, galaxy_y, mean_embedding')
503→            .eq('user_id', userId)
504→            .single();
505→
506→        if (!centroid || centroid.galaxy_x == null) return;
507→
508→        const { data: userPosts } = await supabase
509→            .from('journals')
510→            .select('id, embeddings')
511→            .eq('user_id', userId)
512→            .eq('privacy', 'public')
513→            .not('embeddings', 'is', null)
514→            .order('created_at', { ascending: true });
515→
516→        if (!userPosts) return;
517→
518→        // Get neighbor centroids
519→        const { data: edges } = await supabase
520→            .from('galaxy_edges')
521→            .select('user_a, user_b, similarity')
522→            .or(`user_a.eq.${userId},user_b.eq.${userId}`)
523→            .gte('similarity', 0.3);
524→
525→        const neighborIds = (edges || []).map(e =>
526→            e.user_a === userId ? e.user_b : e.user_a
527→        );
528→
529→        let neighborCentroids = [];
530→        if (neighborIds.length > 0) {
531→            const { data: ncs } = await supabase
532→                .from('galaxy_centroids')
533→                .select('user_id, galaxy_x, galaxy_y, mean_embedding')
534→                .in('user_id', neighborIds)
535→                .not('galaxy_x', 'is', null);
536→            neighborCentroids = ncs || [];
537→        }
538→
539→        for (let idx = 0; idx < userPosts.length; idx++) {
540→            const post = userPosts[idx];
541→            const offset = spiralLayout(idx);
542→            let baseX = centroid.galaxy_x + offset.dx;
543→            let baseY = centroid.galaxy_y + offset.dy;
544→
545→            let pullX = 0;
546→            let pullY = 0;
547→
548→            if (post.embeddings && Array.isArray(post.embeddings)) {
549→                for (const nc of neighborCentroids) {
550→                    if (!nc.mean_embedding || !Array.isArray(nc.mean_embedding)) continue;
551→                    const sim = dot(post.embeddings, nc.mean_embedding);
552→                    if (sim < 0.4) continue;
553→
554→                    const strength = (sim - 0.4) * STAR_PULL_MAX;
555→                    const dx = nc.galaxy_x - baseX;
556→                    const dy = nc.galaxy_y - baseY;
557→                    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
558→                    pullX += (dx / dist) * strength;
559→                    pullY += (dy / dist) * strength;
560→                }
561→            }
562→
563→            const pullMag = Math.sqrt(pullX * pullX + pullY * pullY);
564→            if (pullMag > STAR_PULL_MAX) {
565→                pullX = (pullX / pullMag) * STAR_PULL_MAX;
566→                pullY = (pullY / pullMag) * STAR_PULL_MAX;
567→            }
568→
569→            await supabase
570→                .from('journals')
571→                .update({
572→                    settled_x: Math.round((baseX + pullX) * 100) / 100,
573→                    settled_y: Math.round((baseY + pullY) * 100) / 100
574→                })
575→                .eq('id', post.id);
576→        }
577→
578→        console.log(`[galaxy-settle] Incremental settle complete for user ${userId}`);
579→    } catch (err) {
580→        console.error('[galaxy-settle] Incremental settle error:', err?.message || err);
581→    }
582→}
