 1→/**
 2→ * Maps a 384-dim embedding vector to an RGB color object { r, g, b }.
 3→ * Uses the first 3 dimensions (normalized via sigmoid) to derive Hue, Saturation, Lightness,
 4→ * then converts HSL → RGB for direct use in canvas gradients.
 5→ * Returns null if no valid embedding is provided.
 6→ */
 7→const sigmoid = (x) => 1 / (1 + Math.exp(-x));
 8→
 9→const hslToRgb = (h, s, l) => {
10→    s /= 100;
11→    l /= 100;
12→    const c = (1 - Math.abs(2 * l - 1)) * s;
13→    const x = c * (1 - Math.abs(((h / 60) % 2) - 1));
14→    const m = l - c / 2;
15→    let r, g, b;
16→
17→    if (h < 60)       { r = c; g = x; b = 0; }
18→    else if (h < 120) { r = x; g = c; b = 0; }
19→    else if (h < 180) { r = 0; g = c; b = x; }
20→    else if (h < 240) { r = 0; g = x; b = c; }
21→    else if (h < 300) { r = x; g = 0; b = c; }
22→    else              { r = c; g = 0; b = x; }
23→
24→    return {
25→        r: Math.round((r + m) * 255),
26→        g: Math.round((g + m) * 255),
27→        b: Math.round((b + m) * 255),
28→    };
29→};
30→
31→const embeddingToColor = (embedding) => {
32→    if (!Array.isArray(embedding) || embedding.length < 3) return null;
33→
34→    const h = sigmoid(embedding[0]) * 360;        // 0–360
35→    const s = 40 + sigmoid(embedding[1]) * 40;     // 40–80%
36→    const l = 30 + sigmoid(embedding[2]) * 30;     // 30–60%
37→
38→    return hslToRgb(h, s, l);
39→};
40→
41→export default embeddingToColor;
